sql:
SELECT due_date
FROM compliance_obligations
WHERE due_date BETWEEN DATE('now') AND DATE('now', '+1 month');

SELECT name
FROM tax_types
WHERE category = 'direct';

SELECT description 
FROM tax_regulations 
WHERE DATE('now') BETWEEN effective_date AND expiration_date;

SELECT COUNT(*) AS due_obligations
FROM compliance_obligations
WHERE due_date BETWEEN '2023-10-01' AND '2023-10-31';

SELECT user_id, message, notification_date
FROM notifications
ORDER BY notification_date DESC;

SELECT MAX(compliance_date) AS most_recent_compliance_date
FROM compliance_status
WHERE regulation_id = 0;

SELECT due_date
FROM compliance_obligations
WHERE due_date BETWEEN DATE('now') AND DATE('now', '+7 days');
